/**
 * Mock API layer — simulates a 400ms network delay.
 * Falls back to mock data when the real backend is unreachable.
 */
import api from './api';
import { mockItems, mockCategories, mockLocations } from './mockData';

const DELAY = 400;
const delay = (ms) => new Promise((res) => setTimeout(res, ms));

// ── In-memory store (mirrors mockData, mutated by create/update/delete) ──────
let _items      = mockItems.map((i) => ({ ...i }));
let _categories = mockCategories.map((c) => ({ ...c }));
let _locations  = mockLocations.map((l) => ({ ...l }));

// ── Helper: try real API, fall back to mock ───────────────────────────────────
async function tryReal(apiFn, fallbackFn) {
  try {
    return await apiFn();
  } catch {
    await delay(DELAY);
    return fallbackFn();
  }
}

// ── Items ─────────────────────────────────────────────────────────────────────

export async function getItems() {
  return tryReal(
    async () => { const r = await api.get('/items/'); return r.data; },
    () => [..._items]
  );
}

export async function getItemById(id) {
  return tryReal(
    async () => { const r = await api.get(`/items/${id}`); return r.data; },
    () => _items.find((i) => i.id === Number(id)) ?? null
  );
}

export async function createItem(payload) {
  return tryReal(
    async () => { const r = await api.post('/items/', payload); return r.data; },
    () => {
      const newItem = { ...payload, id: Math.max(..._items.map((i) => i.id)) + 1 };
      _items.push(newItem);
      return newItem;
    }
  );
}

export async function updateItem(id, payload) {
  return tryReal(
    async () => { const r = await api.put(`/items/${id}`, payload); return r.data; },
    () => {
      const idx = _items.findIndex((i) => i.id === Number(id));
      if (idx === -1) throw new Error('Not found');
      _items[idx] = { ..._items[idx], ...payload };
      return _items[idx];
    }
  );
}

export async function deleteItem(id) {
  return tryReal(
    async () => { await api.delete(`/items/${id}`); return true; },
    () => {
      _items = _items.filter((i) => i.id !== Number(id));
      return true;
    }
  );
}

export async function getLowStockItems() {
  return tryReal(
    async () => { const r = await api.get('/items/low-stock'); return r.data; },
    () => _items.filter((i) => i.stock_count < 10)
  );
}

// ── Categories ────────────────────────────────────────────────────────────────

export async function getCategories() {
  return tryReal(
    async () => { const r = await api.get('/categories/'); return r.data; },
    () => [..._categories]
  );
}

export async function createCategory(payload) {
  return tryReal(
    async () => { const r = await api.post('/categories/', payload); return r.data; },
    () => {
      const newCat = { ...payload, id: Math.max(..._categories.map((c) => c.id)) + 1 };
      _categories.push(newCat);
      return newCat;
    }
  );
}

// ── Locations (mock-only) ─────────────────────────────────────────────────────

export async function getLocations() {
  await delay(DELAY);
  return [..._locations];
}

export async function createLocation(payload) {
  await delay(DELAY);
  const newLoc = { ...payload, id: Math.max(..._locations.map((l) => l.id)) + 1, used: 0 };
  _locations.push(newLoc);
  return newLoc;
}

export async function updateLocation(id, payload) {
  await delay(DELAY);
  const idx = _locations.findIndex((l) => l.id === Number(id));
  if (idx === -1) throw new Error('Not found');
  _locations[idx] = { ..._locations[idx], ...payload };
  return _locations[idx];
}

export async function deleteLocation(id) {
  await delay(DELAY);
  _locations = _locations.filter((l) => l.id !== Number(id));
  return true;
}

// ── Dashboard stats ───────────────────────────────────────────────────────────

export async function getDashboardStats() {
  await delay(DELAY);
  const items = [..._items];
  return {
    totalItems:     items.length,
    totalQuantity:  items.reduce((s, i) => s + i.stock_count, 0),
    lowStockCount:  items.filter((i) => i.stock_count < 10).length,
    totalLocations: _locations.length,
    totalValue:     items.reduce((s, i) => s + i.stock_count * i.price, 0),
    recentItems:    [...items].sort((a, b) => b.id - a.id).slice(0, 5),
    lowStockItems:  items.filter((i) => i.stock_count < 10).slice(0, 5),
  };
}

// ── Auth ──────────────────────────────────────────────────────────────────────

export async function login(username, password) {
  return tryReal(
    async () => {
      const r = await api.post('/users/login', { username, password });
      return r.data;
    },
    () => {
      // Demo fallback: any username + "password123"
      if (password !== 'password123') throw new Error('Invalid credentials');
      const mockUsers = [
        { id: 1, username: 'admin',   role: 'admin'   },
        { id: 2, username: 'manager', role: 'manager' },
        { id: 3, username: 'staff',   role: 'staff'   },
      ];
      const user = mockUsers.find((u) => u.username === username) ?? mockUsers[0];
      return { user, access_token: 'mock-token', token_type: 'bearer' };
    }
  );
}
